  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `submitted_by` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `submitted_at` datetime DEFAULT NULL,
  PRIMARY KEY (`session_id`),
  UNIQUE KEY `session_code` (`session_code`),
  KEY `course_id` (`course_id`),
  KEY `duration_id` (`duration_id`),
  KEY `training_type_id` (`training_type_id`),
  KEY `location_id` (`location_id`),
  KEY `fac_level_id` (`fac_level_id`),
  KEY `county_id` (`county_id`),
  KEY `subcounty_id` (`subcounty_id`),
  CONSTRAINT `training_sessions_ibfk_1` FOREIGN KEY (`course_id`) REFERENCES `courses` (`course_id`),
  CONSTRAINT `training_sessions_ibfk_2` FOREIGN KEY (`duration_id`) REFERENCES `course_durations` (`duration_id`),
  CONSTRAINT `training_sessions_ibfk_3` FOREIGN KEY (`training_type_id`) REFERENCES `training_types` (`trainingtype_id`),
  CONSTRAINT `training_sessions_ibfk_4` FOREIGN KEY (`location_id`) REFERENCES `training_locations` (`location_id`),
  CONSTRAINT `training_sessions_ibfk_5` FOREIGN KEY (`fac_level_id`) REFERENCES `facilitator_levels` (`fac_level_id`),
  CONSTRAINT `training_sessions_ibfk_6` FOREIGN KEY (`county_id`) REFERENCES `counties` (`county_id`),
  CONSTRAINT `training_sessions_ibfk_7` FOREIGN KEY (`subcounty_id`) REFERENCES `sub_counties` (`sub_county_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




